import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../context/AuthContext';
import * as api from '../services/api';
import SubscriptionCard from '../components/shared/SubscriptionCard';
import Modal from '../components/shared/Modal';
import './Subscribe.css';

const PLANS = {
  monthly: {
    label: 'Monthly',
    price: '₹100',
    period: '/month',
    total: '₹100/mo',
    saving: null,
    days: 30,
    features: ['Monthly prize draw entry', 'Score tracking (5 scores)', 'Charity contribution', '30-day access']
  },
  yearly: {
    label: 'Yearly',
    price: '₹1,000',
    period: '/year',
    total: '₹84/mo',
    saving: 'Save 20%',
    days: 365,
    features: ['Monthly prize draw entry', 'Score tracking (5 scores)', 'Charity contribution', '365-day access', 'Priority support']
  },
};

export default function Subscribe() {
  const { user, isSubscribed, refreshUser } = useAuth();
  const navigate = useNavigate();
  const [selected, setSelected] = useState('monthly');
  const [loading, setLoading] = useState(false);
  const [isCancelModalOpen, setIsCancelModalOpen] = useState(false);

  const handleSubscribe = async () => {
    if (!user) {
      navigate('/register');
      return;
    }

    setLoading(true);
    try {
      const res = await api.activateSubscription(selected);
      await refreshUser();
      const endDate = new Date(res.data.user.subscriptionEndDate).toLocaleDateString('en-IN', {
        day: 'numeric', month: 'long', year: 'numeric',
      });
      toast.success(`🎉 ${PLANS[selected].label} plan activated! Valid until ${endDate}`);
      navigate('/dashboard');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Could not activate subscription. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleCancel = async () => {
    try {
      await api.cancelSubscription();
      await refreshUser();
      toast.info('Subscription cancelled.');
    } catch (err) {
      toast.error('Could not cancel subscription.');
    }
    setIsCancelModalOpen(false);
  };

  return (
    <div className="subscribe-page page">
      <div className="container-sm">
        <div className="sub-header">
          <div className="section-label">Membership</div>
          <h1>Choose your plan</h1>
          <p>Every subscription enters you into monthly draws and funds your chosen charity.</p>
        </div>

        {isSubscribed() && (
          <div className="card sub-active-notice glow-green">
            <span className="badge badge-green">✓ Active Subscriber</span>
            <p>
              You are on the <strong>{user.plan}</strong> plan.
              Valid until{' '}
              <strong>
                {new Date(user.subscriptionEndDate).toLocaleDateString('en-IN', {
                  day: 'numeric', month: 'long', year: 'numeric',
                })}
              </strong>.
            </p>
            <p style={{ fontSize: '0.85rem', color: 'var(--text-muted)', marginTop: '0.25rem' }}>
              Selecting a plan below will <strong>extend</strong> your current subscription.
            </p>
            <div style={{ display: 'flex', gap: '0.75rem', marginTop: '1rem', flexWrap: 'wrap' }}>
              <button className="btn btn-outline btn-sm" onClick={() => navigate('/dashboard')}>
                Go to Dashboard
              </button>
              <button className="btn btn-danger btn-sm" onClick={() => setIsCancelModalOpen(true)}>
                Cancel Subscription
              </button>
            </div>
          </div>
        )}

        <div className="plan-cards" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '1.5rem', marginBottom: '2rem' }}>
          {Object.entries(PLANS).map(([key, plan]) => (
            <SubscriptionCard
              key={key}
              plan={plan.label}
              isSelected={selected === key}
              onSelect={() => setSelected(key)}
              price={plan.price}
              period={plan.period}
              total={plan.total}
              saving={plan.saving}
              days={plan.days}
              features={plan.features}
            />
          ))}
        </div>

        <button
          id="subscribe-btn"
          className="btn btn-primary btn-full btn-lg transition-all"
          onClick={handleSubscribe}
          disabled={loading}
          style={{ marginBottom: '2rem' }}
        >
          {loading
            ? 'Activating…'
            : isSubscribed()
              ? `Extend with ${PLANS[selected].label} Plan →`
              : `Subscribe ${PLANS[selected].label} →`}
        </button>

        <div className="sub-breakdown card">
          <h3>Where your subscription goes</h3>
          <div className="breakdown-items">
            <div className="breakdown-item">
              <span>Prize Pool</span>
              <span className="breakdown-pct">90%</span>
            </div>
            <div className="progress-container">
              <div className="progress-fill" style={{ width: '90%' }} />
            </div>
            <div className="breakdown-item" style={{ marginTop: '1rem' }}>
              <span>Charity (min 10%)</span>
              <span className="breakdown-pct">10%+</span>
            </div>
            <div className="progress-container">
              <div className="progress-fill" style={{ width: '10%', background: 'var(--gold)', boxShadow: '0 0 10px var(--gold)' }} />
            </div>
          </div>
        </div>

        <p className="sub-note" style={{ textAlign: 'center', marginTop: '2rem' }}>
          Instant activation. No payment required during preview.
        </p>
      </div>

      <Modal
        isOpen={isCancelModalOpen}
        onClose={() => setIsCancelModalOpen(false)}
        onConfirm={handleCancel}
        title="Cancel Subscription?"
        message="You will retain access until your current period ends. Are you sure you want to proceed?"
        confirmText="Yes, Cancel"
        type="danger"
      />
    </div>
  );
}
